from detectron2.config import CfgNode as CN


def add_maskformer2_config(cfg):
    """
    Add config for MASK_FORMER.
    """
    # NOTE: configs from original maskformer
    # data config
    # select the dataset mapper
    cfg.INPUT.DATASET_MAPPER_NAME = "mask_former_semantic"
    # Color augmentation
    cfg.INPUT.COLOR_AUG_SSD = False
    # We retry random cropping until no single category in semantic segmentation GT occupies more
    # than `SINGLE_CATEGORY_MAX_AREA` part of the crop.
    cfg.INPUT.CROP.SINGLE_CATEGORY_MAX_AREA = 1.0
    # Pad image and segmentation GT in dataset mapper.
    cfg.INPUT.SIZE_DIVISIBILITY = -1

    # Event input. These defaults keep RGB-only behavior unless a dataset record
    # provides event_h5/event_old/event_new and MODEL.EVENT_FUSION is enabled.
    cfg.INPUT.EVENT = CN()
    cfg.INPUT.EVENT.NUM_BINS = 5
    cfg.INPUT.EVENT.SUPPORT_PERCENTILE = 50.0
    cfg.INPUT.EVENT.TEMPORAL_THRESHOLD = 0.05
    cfg.INPUT.EVENT.SUPPORT_DILATION = 1
    cfg.INPUT.EVENT.DROPOUT_PROB = 0.15
    cfg.INPUT.EVENT.BIN_DROPOUT_PROB = 0.10
    cfg.INPUT.EVENT.EDGE_DROPOUT_PROB = 0.0
    cfg.INPUT.EVENT.ZERO_EVENT = False
    cfg.INPUT.EVENT.EDGE_WINDOW_RADII_MS = []
    cfg.INPUT.EVENT.BOUNDARY_RADII = []

    # solver config
    # weight decay on embedding
    cfg.SOLVER.WEIGHT_DECAY_EMBED = 0.0
    # optimizer
    cfg.SOLVER.OPTIMIZER = "ADAMW"
    cfg.SOLVER.BACKBONE_MULTIPLIER = 0.1

    # Generic fine-tuning control. When non-empty, the trainer freezes the
    # whole model and only enables parameters whose names start with a prefix.
    cfg.MODEL.TRAINABLE_PREFIXES = []

    # mask_former model config
    cfg.MODEL.MASK_FORMER = CN()

    # loss
    cfg.MODEL.MASK_FORMER.DEEP_SUPERVISION = True
    cfg.MODEL.MASK_FORMER.NO_OBJECT_WEIGHT = 0.1
    cfg.MODEL.MASK_FORMER.CLASS_WEIGHT = 1.0
    cfg.MODEL.MASK_FORMER.DICE_WEIGHT = 1.0
    cfg.MODEL.MASK_FORMER.MASK_WEIGHT = 20.0

    # transformer config
    cfg.MODEL.MASK_FORMER.NHEADS = 8
    cfg.MODEL.MASK_FORMER.DROPOUT = 0.1
    cfg.MODEL.MASK_FORMER.DIM_FEEDFORWARD = 2048
    cfg.MODEL.MASK_FORMER.ENC_LAYERS = 0
    cfg.MODEL.MASK_FORMER.DEC_LAYERS = 6
    cfg.MODEL.MASK_FORMER.PRE_NORM = False

    cfg.MODEL.MASK_FORMER.HIDDEN_DIM = 256
    cfg.MODEL.MASK_FORMER.NUM_OBJECT_QUERIES = 100

    cfg.MODEL.MASK_FORMER.TRANSFORMER_IN_FEATURE = "res5"
    cfg.MODEL.MASK_FORMER.ENFORCE_INPUT_PROJ = False

    # mask_former inference config
    cfg.MODEL.MASK_FORMER.TEST = CN()
    cfg.MODEL.MASK_FORMER.TEST.SEMANTIC_ON = True
    cfg.MODEL.MASK_FORMER.TEST.INSTANCE_ON = False
    cfg.MODEL.MASK_FORMER.TEST.PANOPTIC_ON = False
    cfg.MODEL.MASK_FORMER.TEST.OBJECT_MASK_THRESHOLD = 0.0
    cfg.MODEL.MASK_FORMER.TEST.OVERLAP_THRESHOLD = 0.0
    cfg.MODEL.MASK_FORMER.TEST.SEM_SEG_POSTPROCESSING_BEFORE_INFERENCE = False

    # Sometimes `backbone.size_divisibility` is set to 0 for some backbone (e.g. ResNet)
    # you can use this config to override
    cfg.MODEL.MASK_FORMER.SIZE_DIVISIBILITY = 32

    # Conservative RGB-event correction branch. The base Mask2Former losses are
    # unchanged; event modules learn through the segmentation objective.
    cfg.MODEL.EVENT_FUSION = CN()
    cfg.MODEL.EVENT_FUSION.ENABLED = False
    cfg.MODEL.EVENT_FUSION.IN_CHANNELS = 10
    cfg.MODEL.EVENT_FUSION.STAT_CHANNELS = 4
    cfg.MODEL.EVENT_FUSION.STAGES = ["res3", "res4"]
    cfg.MODEL.EVENT_FUSION.HIDDEN_DIM = 128
    cfg.MODEL.EVENT_FUSION.INIT_ALPHA = 0.05
    cfg.MODEL.EVENT_FUSION.GATE_BIAS = -2.0
    cfg.MODEL.EVENT_FUSION.USE_RELIABILITY_PRIOR = False
    cfg.MODEL.EVENT_FUSION.RELIABILITY_DENSITY_POWER = 0.5
    cfg.MODEL.EVENT_FUSION.RELIABILITY_TEMPORAL_POWER = 1.0
    cfg.MODEL.EVENT_FUSION.RELIABILITY_POLARITY_POWER = 0.25
    cfg.MODEL.EVENT_FUSION.RELIABILITY_FLOOR = 1.0
    cfg.MODEL.EVENT_FUSION.RELIABILITY_GAIN = 0.0
    cfg.MODEL.EVENT_FUSION.GATE_SPARSITY_WEIGHT = 0.0
    cfg.MODEL.EVENT_FUSION.GATE_INVALID_WEIGHT = 0.0
    cfg.MODEL.EVENT_FUSION.LOG_GATE_STATS = True
    cfg.MODEL.EVENT_FUSION.TRAIN_ONLY_EVENT = False

    # Event edge-semantic pretraining/refinement branch. Defaults are disabled
    # so existing RGB-only and event-fusion configs keep their behavior.
    cfg.MODEL.EVENT_EDGE = CN()
    cfg.MODEL.EVENT_EDGE.ENABLED = False
    cfg.MODEL.EVENT_EDGE.IN_CHANNELS = 0
    cfg.MODEL.EVENT_EDGE.HIDDEN_DIM = 64
    cfg.MODEL.EVENT_EDGE.USE_RGB_FEATURE = True
    cfg.MODEL.EVENT_EDGE.RGB_FEATURE = "res2"
    cfg.MODEL.EVENT_EDGE.DETACH_RGB_FEATURE = True
    cfg.MODEL.EVENT_EDGE.OUTPUT_STRIDE = 4
    cfg.MODEL.EVENT_EDGE.PRIMARY_BOUNDARY_RADIUS = 3
    cfg.MODEL.EVENT_EDGE.BCE_WEIGHT = 1.0
    cfg.MODEL.EVENT_EDGE.DICE_WEIGHT = 1.0
    cfg.MODEL.EVENT_EDGE.POS_WEIGHT_MAX = 20.0
    cfg.MODEL.EVENT_EDGE.LOG_EDGE_STATS = True
    cfg.MODEL.EVENT_EDGE.TRAIN_ONLY_EDGE = False
    cfg.MODEL.EVENT_EDGE.CLASS_AWARE = False
    cfg.MODEL.EVENT_EDGE.NUM_CLASSES = 19
    cfg.MODEL.EVENT_EDGE.CLASS_BOUNDARY_RADIUS = 3
    cfg.MODEL.EVENT_EDGE.CLASS_BCE_WEIGHT = 0.5
    cfg.MODEL.EVENT_EDGE.CLASS_POS_WEIGHT_MAX = 20.0

    # Edge-guided segmentation adapter. This consumes the learned event edge
    # feature and applies a gated residual correction to one backbone feature.
    cfg.MODEL.EVENT_EDGE_GUIDE = CN()
    cfg.MODEL.EVENT_EDGE_GUIDE.ENABLED = False
    cfg.MODEL.EVENT_EDGE_GUIDE.STAGE = "res2"
    cfg.MODEL.EVENT_EDGE_GUIDE.INIT_ALPHA = 0.05
    cfg.MODEL.EVENT_EDGE_GUIDE.GATE_BIAS = -2.0
    cfg.MODEL.EVENT_EDGE_GUIDE.EDGE_PROB_POWER = 1.0
    cfg.MODEL.EVENT_EDGE_GUIDE.USE_EVENT_RELIABILITY = True
    cfg.MODEL.EVENT_EDGE_GUIDE.RELIABILITY_FLOOR = 0.25
    cfg.MODEL.EVENT_EDGE_GUIDE.LOW_LIGHT_ENABLED = True
    cfg.MODEL.EVENT_EDGE_GUIDE.LOW_LIGHT_GAIN = 1.0
    cfg.MODEL.EVENT_EDGE_GUIDE.LOW_LIGHT_LUMA_THRESHOLD = 0.35
    cfg.MODEL.EVENT_EDGE_GUIDE.LOW_LIGHT_CONTRAST_THRESHOLD = 0.08
    cfg.MODEL.EVENT_EDGE_GUIDE.SCORE_PREDICTOR_ENABLED = False
    cfg.MODEL.EVENT_EDGE_GUIDE.SCORE_SPARSITY_WEIGHT = 0.0
    cfg.MODEL.EVENT_EDGE_GUIDE.GATE_SPARSITY_WEIGHT = 0.0
    cfg.MODEL.EVENT_EDGE_GUIDE.NON_BOUNDARY_GATE_WEIGHT = 0.0
    cfg.MODEL.EVENT_EDGE_GUIDE.LOG_STATS = True
    cfg.MODEL.EVENT_EDGE_GUIDE.TRAIN_ONLY_GUIDE = False
    cfg.MODEL.EVENT_EDGE_GUIDE.TRAIN_WITH_SEM_SEG_HEAD = False
    cfg.MODEL.EVENT_EDGE_GUIDE.TRAIN_EDGE_HEAD = True
    cfg.MODEL.EVENT_EDGE_GUIDE.TRAINABLE_PREFIXES = []

    # Early event-edge adapter. This applies a tiny residual correction right
    # after Swin patch embedding, using event edge/reliability only where the
    # RGB segmentation is wrong or uncertain near boundaries.
    cfg.MODEL.EARLY_EVENT_EDGE_ADAPTER = CN()
    cfg.MODEL.EARLY_EVENT_EDGE_ADAPTER.ENABLED = False
    cfg.MODEL.EARLY_EVENT_EDGE_ADAPTER.IN_CHANNELS = 9
    cfg.MODEL.EARLY_EVENT_EDGE_ADAPTER.STAT_CHANNELS = 4
    cfg.MODEL.EARLY_EVENT_EDGE_ADAPTER.HIDDEN_DIM = 64
    cfg.MODEL.EARLY_EVENT_EDGE_ADAPTER.INIT_ALPHA = 0.001
    cfg.MODEL.EARLY_EVENT_EDGE_ADAPTER.ALPHA_MAX = 0.02
    cfg.MODEL.EARLY_EVENT_EDGE_ADAPTER.GATE_BIAS = -5.0
    cfg.MODEL.EARLY_EVENT_EDGE_ADAPTER.EDGE_PROB_POWER = 2.0
    cfg.MODEL.EARLY_EVENT_EDGE_ADAPTER.USE_EVENT_RELIABILITY = True
    cfg.MODEL.EARLY_EVENT_EDGE_ADAPTER.RELIABILITY_FLOOR = 0.10
    cfg.MODEL.EARLY_EVENT_EDGE_ADAPTER.RELIABILITY_THRESHOLD = 0.05
    cfg.MODEL.EARLY_EVENT_EDGE_ADAPTER.EVENT_EDGE_THRESHOLD = 0.20
    cfg.MODEL.EARLY_EVENT_EDGE_ADAPTER.CONFIDENCE_THRESHOLD = 0.65
    cfg.MODEL.EARLY_EVENT_EDGE_ADAPTER.MARGIN_THRESHOLD = 0.25
    cfg.MODEL.EARLY_EVENT_EDGE_ADAPTER.ENTROPY_THRESHOLD = 0.55
    cfg.MODEL.EARLY_EVENT_EDGE_ADAPTER.REQUIRE_BOUNDARY = True
    cfg.MODEL.EARLY_EVENT_EDGE_ADAPTER.BOUNDARY_RADIUS = 3
    cfg.MODEL.EARLY_EVENT_EDGE_ADAPTER.GATE_BCE_WEIGHT = 0.10
    cfg.MODEL.EARLY_EVENT_EDGE_ADAPTER.GATE_POSITIVE_WEIGHT = 4.0
    cfg.MODEL.EARLY_EVENT_EDGE_ADAPTER.GATE_NEGATIVE_WEIGHT = 1.0
    cfg.MODEL.EARLY_EVENT_EDGE_ADAPTER.GATE_SUPERVISION_DETACH = True
    cfg.MODEL.EARLY_EVENT_EDGE_ADAPTER.GATE_SUPERVISION_TARGET = "final"
    cfg.MODEL.EARLY_EVENT_EDGE_ADAPTER.ALLOW_PRED_CLASSES = []
    cfg.MODEL.EARLY_EVENT_EDGE_ADAPTER.DENY_PRED_CLASSES = []
    cfg.MODEL.EARLY_EVENT_EDGE_ADAPTER.ALLOW_TARGET_CLASSES = []
    cfg.MODEL.EARLY_EVENT_EDGE_ADAPTER.DENY_TARGET_CLASSES = []
    cfg.MODEL.EARLY_EVENT_EDGE_ADAPTER.LOG_STATS = True

    # Preserve the strong RGB path while event guidance learns where to modify.
    # This uses the pre-event-guide dense semantic prediction from the same
    # forward pass as a detached teacher, and applies KL only on confident
    # non-boundary / non-event-edge safe regions.
    cfg.MODEL.EVENT_PRESERVE = CN()
    cfg.MODEL.EVENT_PRESERVE.ENABLED = False
    cfg.MODEL.EVENT_PRESERVE.WEIGHT = 0.2
    cfg.MODEL.EVENT_PRESERVE.CONFIDENCE_THRESHOLD = 0.65
    cfg.MODEL.EVENT_PRESERVE.MARGIN_THRESHOLD = 0.25
    cfg.MODEL.EVENT_PRESERVE.EVENT_EDGE_THRESHOLD = 0.25
    cfg.MODEL.EVENT_PRESERVE.USE_BOUNDARY_TARGET = True
    cfg.MODEL.EVENT_PRESERVE.USE_EVENT_EDGE = True
    cfg.MODEL.EVENT_PRESERVE.LOG_STATS = True

    # Day-only logit-level event boundary refiner. This keeps the RGB
    # backbone/decoder frozen and applies a sparse top-k semantic correction
    # only after dense Mask2Former probabilities are produced.
    cfg.MODEL.DAY_EVENT_BOUNDARY_REFINER = CN()
    cfg.MODEL.DAY_EVENT_BOUNDARY_REFINER.ENABLED = False
    cfg.MODEL.DAY_EVENT_BOUNDARY_REFINER.NUM_CLASSES = 19
    cfg.MODEL.DAY_EVENT_BOUNDARY_REFINER.EDGE_CHANNELS = 64
    cfg.MODEL.DAY_EVENT_BOUNDARY_REFINER.HIDDEN_DIM = 64
    cfg.MODEL.DAY_EVENT_BOUNDARY_REFINER.INIT_ALPHA = 0.01
    cfg.MODEL.DAY_EVENT_BOUNDARY_REFINER.GATE_BIAS = -4.0
    cfg.MODEL.DAY_EVENT_BOUNDARY_REFINER.FINAL_GATE_SCALE = 1.0
    cfg.MODEL.DAY_EVENT_BOUNDARY_REFINER.TOPK_CLASSES = 2
    cfg.MODEL.DAY_EVENT_BOUNDARY_REFINER.TAU_MARGIN = 0.30
    cfg.MODEL.DAY_EVENT_BOUNDARY_REFINER.ENTROPY_THRESHOLD = 0.50
    cfg.MODEL.DAY_EVENT_BOUNDARY_REFINER.UNCERTAIN_FRACTION = 0.20
    cfg.MODEL.DAY_EVENT_BOUNDARY_REFINER.EDGE_THRESHOLD = 0.30
    cfg.MODEL.DAY_EVENT_BOUNDARY_REFINER.EDGE_PROB_POWER = 2.0
    cfg.MODEL.DAY_EVENT_BOUNDARY_REFINER.BOUNDARY_RADIUS = 3
    cfg.MODEL.DAY_EVENT_BOUNDARY_REFINER.BOUNDARY_WEIGHT = 0.5
    cfg.MODEL.DAY_EVENT_BOUNDARY_REFINER.USE_EVENT_RELIABILITY = True
    cfg.MODEL.DAY_EVENT_BOUNDARY_REFINER.USE_RGB_UNCERTAINTY = True
    cfg.MODEL.DAY_EVENT_BOUNDARY_REFINER.USE_SEMANTIC_BOUNDARY = True
    cfg.MODEL.DAY_EVENT_BOUNDARY_REFINER.REQUIRE_UNCERTAIN_BOUNDARY_INTERSECTION = False
    cfg.MODEL.DAY_EVENT_BOUNDARY_REFINER.REQUIRE_EVENT_ACTIVE = True
    cfg.MODEL.DAY_EVENT_BOUNDARY_REFINER.EVENT_ACTIVE_SOURCE = "density"
    cfg.MODEL.DAY_EVENT_BOUNDARY_REFINER.EVENT_ACTIVE_THRESHOLD = 0.0
    cfg.MODEL.DAY_EVENT_BOUNDARY_REFINER.PRESERVE_CONFIDENCE_THRESHOLD = 0.70
    cfg.MODEL.DAY_EVENT_BOUNDARY_REFINER.PRESERVE_MARGIN_THRESHOLD = 0.30
    cfg.MODEL.DAY_EVENT_BOUNDARY_REFINER.MIN_CONFIDENCE_FOR_CORRECTION = 0.0
    cfg.MODEL.DAY_EVENT_BOUNDARY_REFINER.MIN_MARGIN_FOR_CORRECTION = 0.0
    cfg.MODEL.DAY_EVENT_BOUNDARY_REFINER.LOSS_BOUNDARY_CE_WEIGHT = 1.0
    cfg.MODEL.DAY_EVENT_BOUNDARY_REFINER.LOSS_UNCERTAIN_CE_WEIGHT = 0.5
    cfg.MODEL.DAY_EVENT_BOUNDARY_REFINER.LOSS_PRESERVE_KL_WEIGHT = 1.0
    cfg.MODEL.DAY_EVENT_BOUNDARY_REFINER.LOSS_GATE_SPARSE_WEIGHT = 0.005
    cfg.MODEL.DAY_EVENT_BOUNDARY_REFINER.LOSS_GATE_INVALID_WEIGHT = 0.010
    cfg.MODEL.DAY_EVENT_BOUNDARY_REFINER.LOSS_DELTA_NON_BOUNDARY_WEIGHT = 0.001
    cfg.MODEL.DAY_EVENT_BOUNDARY_REFINER.LOSS_CANDIDATE_CE_WEIGHT = 0.0
    cfg.MODEL.DAY_EVENT_BOUNDARY_REFINER.CANDIDATE_CE_REPAIR_POSITIVE_ONLY = False
    cfg.MODEL.DAY_EVENT_BOUNDARY_REFINER.CANDIDATE_LOGIT_SCALE = 1.0
    cfg.MODEL.DAY_EVENT_BOUNDARY_REFINER.LOSS_ALLOWED_ONLY = False
    cfg.MODEL.DAY_EVENT_BOUNDARY_REFINER.LOSS_ALLOWED_SOFT_THRESHOLD = 0.0
    cfg.MODEL.DAY_EVENT_BOUNDARY_REFINER.CLASS_GATE_WEIGHTS = []
    cfg.MODEL.DAY_EVENT_BOUNDARY_REFINER.CLASS_GATE_LOSS_THRESHOLD = 0.0
    cfg.MODEL.DAY_EVENT_BOUNDARY_REFINER.EDGE_ONLY_CORRECTION = False
    cfg.MODEL.DAY_EVENT_BOUNDARY_REFINER.SCORE_PREDICTOR_ENABLED = False
    cfg.MODEL.DAY_EVENT_BOUNDARY_REFINER.SCORE_BCE_WEIGHT = 0.0
    cfg.MODEL.DAY_EVENT_BOUNDARY_REFINER.SCORE_SPARSITY_WEIGHT = 0.0
    cfg.MODEL.DAY_EVENT_BOUNDARY_REFINER.SCORE_POSITIVE_WEIGHT = 2.0
    cfg.MODEL.DAY_EVENT_BOUNDARY_REFINER.SCORE_NEGATIVE_WEIGHT = 1.0
    cfg.MODEL.DAY_EVENT_BOUNDARY_REFINER.SELECTIVE_REPAIR_GATE_ENABLED = False
    cfg.MODEL.DAY_EVENT_BOUNDARY_REFINER.LOSS_REPAIR_GATE_BCE_WEIGHT = 0.0
    cfg.MODEL.DAY_EVENT_BOUNDARY_REFINER.REPAIR_GATE_POSITIVE_WEIGHT = 4.0
    cfg.MODEL.DAY_EVENT_BOUNDARY_REFINER.REPAIR_GATE_NEGATIVE_WEIGHT = 1.0
    cfg.MODEL.DAY_EVENT_BOUNDARY_REFINER.REPAIR_REQUIRE_TARGET_IN_TOPK = True
    cfg.MODEL.DAY_EVENT_BOUNDARY_REFINER.REPAIR_SUPERVISE_SCORE = False
    cfg.MODEL.DAY_EVENT_BOUNDARY_REFINER.REPAIR_CLASS_WEIGHTS = []
    cfg.MODEL.DAY_EVENT_BOUNDARY_REFINER.PAIR_AWARE_ENABLED = False
    cfg.MODEL.DAY_EVENT_BOUNDARY_REFINER.PAIR_ALLOW_WEIGHTS = []
    cfg.MODEL.DAY_EVENT_BOUNDARY_REFINER.PAIR_SUPPRESS_WEIGHTS = []
    cfg.MODEL.DAY_EVENT_BOUNDARY_REFINER.PAIR_WEIGHT_DEFAULT = 1.0
    cfg.MODEL.DAY_EVENT_BOUNDARY_REFINER.HARD_PAIR_GATE_ENABLED = False
    cfg.MODEL.DAY_EVENT_BOUNDARY_REFINER.HARD_PAIR_GATE_THRESHOLD = 1.0
    cfg.MODEL.DAY_EVENT_BOUNDARY_REFINER.HARD_PAIR_GATE_INCLUDE_IDENTITY = False
    cfg.MODEL.DAY_EVENT_BOUNDARY_REFINER.HARD_PAIR_SUPPRESS_ENABLED = False
    cfg.MODEL.DAY_EVENT_BOUNDARY_REFINER.LOSS_PAIR_SUPPRESS_GATE_WEIGHT = 0.0
    cfg.MODEL.DAY_EVENT_BOUNDARY_REFINER.LOSS_PAIR_SUPPRESS_DELTA_WEIGHT = 0.0
    cfg.MODEL.DAY_EVENT_BOUNDARY_REFINER.DETACH_BASE_PROB = True
    cfg.MODEL.DAY_EVENT_BOUNDARY_REFINER.SKIP_MASK2FORMER_LOSS = False
    cfg.MODEL.DAY_EVENT_BOUNDARY_REFINER.LOG_STATS = True

    # Optional epoch-style wrapper around Detectron2's iteration scheduler.
    cfg.TRAIN = CN()
    cfg.TRAIN.EPOCHS = 0
    cfg.TRAIN.NUM_TRAIN_SAMPLES = 0
    cfg.TRAIN.EVAL_EVERY_EPOCH = True
    cfg.TRAIN.CHECKPOINT_EVERY_EPOCH = True
    cfg.TRAIN.BEST_CHECKPOINT_MIN_MIOU = []
    cfg.TRAIN.DISABLE_PERIODIC_CHECKPOINT = False

    # pixel decoder config
    cfg.MODEL.SEM_SEG_HEAD.MASK_DIM = 256
    # adding transformer in pixel decoder
    cfg.MODEL.SEM_SEG_HEAD.TRANSFORMER_ENC_LAYERS = 0
    # pixel decoder
    cfg.MODEL.SEM_SEG_HEAD.PIXEL_DECODER_NAME = "BasePixelDecoder"

    # swin transformer backbone
    cfg.MODEL.SWIN = CN()
    cfg.MODEL.SWIN.PRETRAIN_IMG_SIZE = 224
    cfg.MODEL.SWIN.PATCH_SIZE = 4
    cfg.MODEL.SWIN.EMBED_DIM = 96
    cfg.MODEL.SWIN.DEPTHS = [2, 2, 6, 2]
    cfg.MODEL.SWIN.NUM_HEADS = [3, 6, 12, 24]
    cfg.MODEL.SWIN.WINDOW_SIZE = 7
    cfg.MODEL.SWIN.MLP_RATIO = 4.0
    cfg.MODEL.SWIN.QKV_BIAS = True
    cfg.MODEL.SWIN.QK_SCALE = None
    cfg.MODEL.SWIN.DROP_RATE = 0.0
    cfg.MODEL.SWIN.ATTN_DROP_RATE = 0.0
    cfg.MODEL.SWIN.DROP_PATH_RATE = 0.3
    cfg.MODEL.SWIN.APE = False
    cfg.MODEL.SWIN.PATCH_NORM = True
    cfg.MODEL.SWIN.OUT_FEATURES = ["res2", "res3", "res4", "res5"]
    cfg.MODEL.SWIN.USE_CHECKPOINT = False

    # NOTE: maskformer2 extra configs
    # transformer module
    cfg.MODEL.MASK_FORMER.TRANSFORMER_DECODER_NAME = "MultiScaleMaskedTransformerDecoder"

    # LSJ aug
    cfg.INPUT.IMAGE_SIZE = 1024
    cfg.INPUT.MIN_SCALE = 0.1
    cfg.INPUT.MAX_SCALE = 2.0

    # MSDeformAttn encoder configs
    cfg.MODEL.SEM_SEG_HEAD.DEFORMABLE_TRANSFORMER_ENCODER_IN_FEATURES = ["res3", "res4", "res5"]
    cfg.MODEL.SEM_SEG_HEAD.DEFORMABLE_TRANSFORMER_ENCODER_N_POINTS = 4
    cfg.MODEL.SEM_SEG_HEAD.DEFORMABLE_TRANSFORMER_ENCODER_N_HEADS = 8

    # point loss configs
    # Number of points sampled during training for a mask point head.
    cfg.MODEL.MASK_FORMER.TRAIN_NUM_POINTS = 112 * 112
    # Oversampling parameter for PointRend point sampling during training. Parameter `k` in the
    # original paper.
    cfg.MODEL.MASK_FORMER.OVERSAMPLE_RATIO = 3.0
    # Importance sampling parameter for PointRend point sampling during training. Parametr `beta` in
    # the original paper.
    cfg.MODEL.MASK_FORMER.IMPORTANCE_SAMPLE_RATIO = 0.75
